import 'dart:io';import 'package:dio/dio.dart';import '../core/errors/app_error.dart';import 'models.dart';
class CreateGuestResult{CreateGuestResult(this.user,this.accessToken);final UserProfile user;final String accessToken;}
class ApiRepository{ApiRepository(this.dio);final Dio dio;Future<T> _wrap<T>(Future<T> Function() f)async{try{return await f();}on DioException catch(e){throw AppError.fromDio(e);}}Future<CreateGuestResult> createGuest(String n,String installationId)=>_wrap(()async{final data=(await dio.post('/api/v1/users/guest',data:{'nickname':n,'installationId':installationId})).data as Map<String,Object?>;return CreateGuestResult(UserProfile.fromJson(data['user'] as Map<String,Object?>),((data['session'] as Map)['accessToken']).toString());});Future<UserProfile> me()=>_wrap(()async=>UserProfile.fromJson((await dio.get('/api/v1/users/me')).data));Future<void> logout()=>_wrap(()async{await dio.post('/api/v1/users/me/logout');});Future<Battle?> battle()=>_wrap(()async{final r=await dio.get('/api/v1/battles/next',options:Options(validateStatus:(s)=>s==200||s==204));return r.statusCode==204?null:Battle.fromJson(r.data);});Future<Map<String,Object?>> vote(Battle b,String w)=>_wrap(()async=>(await dio.post('/api/v1/votes',data:{'leftMemeId':b.left.id,'rightMemeId':b.right.id,'winnerMemeId':w})).data);Future<List<MemeItem>> top(String p,{int limit=20})=>_wrap(()async=>(((await dio.get('/api/v1/memes/top',queryParameters:{'period':p,'limit':limit.clamp(1,100)})).data['items']) as List).cast<Map<String,Object?>>().map(MemeItem.fromJson).toList());Future<String> upload(File f)async=>_wrap(()async{final name=f.path.split('/').last;final fd=FormData.fromMap({'file':await MultipartFile.fromFile(f.path,filename:name)});return ((await dio.post('/api/v1/media/images',data:fd)).data['id']).toString();});Future<void> createMeme(String title,String mediaId,String? source)=>_wrap(()async{await dio.post('/api/v1/memes',data:{'title':title,'mediaAssetId':mediaId,'sourceUrl':source?.isEmpty==true?null:source});});}
